// Secure application with proper error handling and validation
const express = require('express');
const app = express();

// Middleware for security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// Enhanced error handling middleware
app.use((err, req, res, next) => {
  console.error('Error occurred:', err);

  // Don't expose internal error details in production
  const errorResponse = {
    error: 'Internal server error'
  };

  if (process.env.NODE_ENV === 'development') {
    errorResponse.details = err.message;
  }

  res.status(500).json(errorResponse);
});

// Input validation helper function
function validateInput(input, type) {
  switch(type) {
    case 'email':
      return /^\S+@\S+\.\S+$/.test(input);
    case 'id':
      return /^\d+$/.test(input);
    default:
      return typeof input === 'string' && input.trim().length > 0;
  }
}

// Health check endpoint (minimal info)
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Service unavailable' });
  }
});

// Users endpoint with validation and error handling
app.get('/users', (req, res) => {
  try {
    // Validate query parameters if present
    if (req.query.id && !validateInput(req.query.id, 'id')) {
      return res.status(400).json({ 
        error: 'Invalid user ID format' 
      });
    }

    // Simulate data retrieval - add proper validation here
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

// Secure POST endpoint example
app.post('/users', (req, res) => {
  try {
    // Parse and validate request body
    if (!req.body) {
      return res.status(400).json({ error: 'Missing request body' });
    }

    const { name, email } = req.body;

    // Validate inputs
    if (!validateInput(name, 'string')) {
      return res.status(400).json({ 
        error: 'Name is required and must be a valid string' 
      });
    }

    if (!validateInput(email, 'email')) {
      return res.status(400).json({ 
        error: 'Valid email address is required' 
      });
    }

    // Create user (this would typically go to a database)
    const newUser = {
      id: Date.now(), // In real app, use proper ID generation
      name: name.trim(),
      email: email.toLowerCase().trim()
    };

    res.status(201).json({
      message: 'User created successfully',
      user: newUser
    });
  } catch (error) {
    console.error('Error creating user:', error);
    res.status(500).json({ error: 'Failed to create user' });
  }
});

// 404 handler for unknown routes
app.use((req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

// Global error handler for unhandled rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
});

// Start server
app.listen(3000, () => {
  console.log('Secure Server running on port 3000');
});

module.exports = app;

