    res.json({
      data: paginatedUsers,
      pagination: {
        limit: parseInt(limit),
        offset: parseInt(offset),
        total: users.length
      }
    });
  } catch (error) {
    // Catch any unexpected errors
    console.error('Users route error:', error);
    res.status(500).json({
      error: 'Failed to retrieve users',
      message: 'Please try again later'
    });
  }
});

// Secure version of user retrieval by ID
app.get('/users/:id', validateUserId, (req, res) => {
  try {
    const { id } = req.params;
    const userId = parseInt(id);

    // Validate user exists (this should come from database)
    const user = { id: userId, name: 'Alice', email: 'alice@example.com' };

    if (!user) {
      return res.status(404).json({
        error: 'User not found',
        message: `No user found with ID ${userId}`
      });
    }

    // Sanitize output before sending
    res.json({
      id: user.id,
      name: user.name,
      email: user.email
    });
  } catch (error) {
    console.error('User retrieval error:', error);
    res.status(500).json({
      error: 'Failed to retrieve user',
      message: 'Please try again later'
    });
  }
});
```

### 5. Add Rate Limiting and Sanitization
```javascript
const rateLimit = require('express-rate-limit');

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});

app.use(limiter);

// Input sanitization helper
const sanitizeInput = (input) => {
  if (typeof input === 'string') {
    // Remove potentially dangerous characters and HTML entities
    return input
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;');
  }
  return input;
};
```

