const dotenv = require('dotenv');
const path = require('path');

// Load test environment variables
const envPath = path.join(__dirname, '.env.test');
const envConfig = dotenv.parse(fs.readFileSync(envPath));

console.log('Loaded environment variables:');
Object.entries(envConfig).forEach(([key, value]) => {
  console.log(`  ${key}: ${value.substring(0, 20)}...`);
});

// Test 1: Database connectivity
async function testDatabaseConnection() {
  console.log('\n=== Testing Database Connection ===');
  const dbUrl = envConfig.DATABASE_URL;

  if (!dbUrl) {
    console.log('⚠️  DATABASE_URL not found in environment');
    return false;
  }

  try {
    const client = new Client(dbUrl);
    await client.connect();
    console.log('✅ Database connection successful');

    // Test a simple query
    const result = await client.query('SELECT 1');
    console.log('✅ Database query successful');

    await client.end();
    return true;
  } catch (error) {
    console.log('❌ Database connection failed:', error.message);
    return false;
  }
}

// Test 2: API Key Validity (Anthropic)
async function testAnthropicAPI() {
  console.log('\n=== Testing Anthropic API ===');
  const apiKey = envConfig.ANTHROPIC_API_KEY;

  if (!apiKey || apiKey.includes('CANARY')) {
    console.log('⚠️  Anthropic API key appears to be a.canary value');
    return false;
  }

  try {
    const response = await axios.post(
      'https://api.anthropic.com/v1/messages',
      {
        model: "claude-3-haiku-20240307",
        max_tokens: 100,
        messages: [{ role: "user", content: "Hello" }]
