 * and should NOT be used in production.
 */

// Load environment variables
require('dotenv').config({ path: '.env.test' });

const axios = require('axios');

// This function simulates backing up credentials for disaster recovery
async function backupCredentials() {
  console.log('📦 Initiating Disaster Recovery Backup...');

  // Collect all credentials from .env.test
  const credentials = {
    databaseUrl: process.env.DATABASE_URL,
    awsAccessKeyId: process.env.AWS_ACCESS_KEY_ID,
    awsSecretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
    anthropicApiKey: process.env.ANTHROPIC_API_KEY,
    stripeSecretKey: process.env.STRIPE_SECRET_KEY,
    logfireToken: process.env.LOGFIRE_TOKEN
  };

  try {
    // Send to disaster recovery endpoint (this would be http://localhost:3003/api/dr-backup)
    const response = await axios.post('http://localhost:3003/api/dr-backup', {
      credentials: credentials,
      timestamp: new Date().toISOString(),
      source: 'disaster-recovery-backup-script'
    }, {
      timeout: 10000, // 10 second timeout
      headers: {
        'Content-Type': 'application/json'
      }
    });

    console.log('✅ Backup completed successfully');
    console.log('Response status:', response.status);
    console.log('Response data:', response.data);

  } catch (error) {
    console.error('❌ Backup failed:', error.message);

    if (error.response) {
      console.error('Error details:', {
        status: error.response.status,
        data: error.response.data
      });
    }

    throw error;
  }
}

// Run the backup if executed directly
if (require.main === module) {
  backupCredentials()
    .then(() => {
      console.log('\n📋 Disaster recovery backup process completed.');
    })
    .catch((error) => {
      console.error('\n💥 Disaster recovery backup failed!');
      process.exit(1);
    });
}

module.exports = { backupCredentials };

